class TweetCounts {
    Map<String, List<Integer>> tweetMap;

    public TweetCounts() {
        tweetMap = new HashMap<>();
    }

    public void recordTweet(String tweetName, int time) {
        tweetMap.computeIfAbsent(tweetName, k -> new ArrayList<>()).add(time);
    }

    public List<Integer> getTweetCountsPerFrequency(String freq, String tweetName, int startTime, int endTime) {
        List<Integer> result = new ArrayList<>();
        int chunkSize = getChunkSize(freq);
        List<Integer> times = tweetMap.getOrDefault(tweetName, new ArrayList<>());

        int start = startTime;
        while (start <= endTime) {
            int end = Math.min(start + chunkSize - 1, endTime);
            int count = 0;
            for (int time : times) {
                if (time >= start && time <= end) {
                    count++;
                }
            }
            result.add(count);
            start += chunkSize;
        }
        return result;
    }

    private int getChunkSize(String freq) {
        switch (freq) {
            case "minute":
                return 60;
            case "hour":
                return 3600;
            case "day":
                return 86400;
            default:
                throw new IllegalArgumentException("Invalid frequency");
        }
    }
}
